INSERT INTO `goals` VALUES (54,29,'I want to become a Software Quality Analyst','2025-08-22 06:23:23','{\"Title\": \"Software Quality Analyst\", \"Long Duration Path\": [{\"Phase\": \"Phase 1: University-Level Foundations (Weeks 1-12)\", \"Steps\": [{\"XPs\": 1000, \"Step\": \"Core Software Engineering Principles\", \"Badges\": \"Engineering Architect\", \"Duration\": 8, \"Provider\": \"NPTEL - Free\", \"Course Link\": \"https://nptel.ac.in/courses/106105182\", \"Description\": \"Build a rock-solid theoretical foundation in software engineering, covering SDLC models, requirements analysis, design principles, and project management. This is crucial for understanding the \'why\' behind testing.\", \"Learning Pace\": \"8-10 hours per week\"}, {\"XPs\": 800, \"Step\": \"Fundamentals of Software Testing\", \"Badges\": \"Testing Theorist\", \"Duration\": 4, \"Provider\": \"NPTEL - Free\", \"Course Link\": \"https://nptel.ac.in/courses/106105150\", \"Description\": \"Dive deep into the theory of software testing, including different levels (unit, integration, system), types (black box, white box), and methodologies. This NPTEL course provides academic rigor.\", \"Learning Pace\": \"8-10 hours per week\"}]}, {\"Phase\": \"Phase 2: Programming & Automation Mastery (Weeks 13-28)\", \"Steps\": [{\"XPs\": 1500, \"Step\": \"Python Programming for Everybody\", \"Badges\": \"Python Scripter\", \"Duration\": 10, \"Provider\": \"Coursera - Partially Free\", \"Course Link\": \"https://www.coursera.org/specializations/python\", \"Description\": \"Gain a comprehensive understanding of Python, from basics to data structures, web scraping, and databases. This specialization is the gold standard for learning Python for practical applications.\", \"Learning Pace\": \"10-12 hours per week\", \"Alternative Free Link\": \"https://www.youtube.com/watch?v=8DvywoWv6fI\"}, {\"XPs\": 1200, \"Step\": \"Advanced Web Automation with Selenium & Python\", \"Badges\": \"Selenium Pro\", \"Duration\": 6, \"Provider\": \"Udemy - Paid\", \"Course Link\": \"https://www.udemy.com/course/selenium-webdriver-with-python3/\", \"Description\": \"Go beyond basic scripts. Learn to build robust, scalable automation frameworks from scratch using Python and Selenium. Master concepts like Page Object Model (POM), data-driven testing, and reporting.\", \"Learning Pace\": \"10-12 hours per week\"}]}, {\"Phase\": \"Phase 3: Advanced Testing & Modern Frameworks (Weeks 29-40)\", \"Steps\": [{\"XPs\": 1000, \"Step\": \"API Automation with Python\", \"Badges\": \"API Automator\", \"Duration\": 4, \"Provider\": \"Udemy - Paid\", \"Course Link\": \"https://www.udemy.com/course/rest-api-automation-testing-rest-assured-java/\", \"Description\": \"Master API testing concepts and learn to automate them using Python\'s `requests` library. The primary link is for a Java/RestAssured course (a very popular stack), but the free alternative provides the Python-based knowledge needed.\", \"Learning Pace\": \"8-10 hours per week\", \"Alternative Free Link\": \"https://www.youtube.com/watch?v=0sOvCdj4x4s\"}, {\"XPs\": 1000, \"Step\": \"Introduction to Modern Test Frameworks\", \"Badges\": \"Modern Tester\", \"Duration\": 4, \"Provider\": \"Test Automation University - Free\", \"Course Link\": \"https://testautomationu.applitools.com/cypress-tutorial/\", \"Description\": \"Stay ahead of the curve by learning a modern, developer-friendly automation framework like Cypress. This will make your profile stand out compared to candidates who only know Selenium.\", \"Learning Pace\": \"10-12 hours per week\"}, {\"XPs\": 800, \"Step\": \"Mobile Application Testing\", \"Badges\": \"Mobile Guardian\", \"Duration\": 4, \"Provider\": \"Udemy - Paid\", \"Course Link\": \"https://www.udemy.com/course/mobile-automation-with-appium-20-and-webdriverio-wdio/\", \"Description\": \"Expand your skills to mobile testing. Learn to use Appium, the leading open-source tool for automating native, hybrid, and mobile web applications on iOS and Android platforms.\", \"Learning Pace\": \"8-10 hours per week\"}]}, {\"Phase\": \"Phase 4: Performance, DevOps & Portfolio (Weeks 41-52)\", \"Steps\": [{\"XPs\": 1200, \"Step\": \"Performance and Load Testing with JMeter\", \"Badges\": \"Performance Engineer\", \"Duration\": 4, \"Provider\": \"Udemy - Paid\", \"Course Link\": \"https://www.udemy.com/course/jmeter-master-performance-load-testing-new-version/\", \"Description\": \"Leverage your interest in networks. Dive deep into non-functional testing by learning to use JMeter for performance, load, and stress testing of web applications and APIs.\", \"Learning Pace\": \"10-12 hours per week\"}, {\"XPs\": 1000, \"Step\": \"Version Control and CI/CD Pipelines\", \"Badges\": \"DevOps Apprentice\", \"Duration\": 4, \"Provider\": \"Udemy - Paid\", \"Course Link\": \"https://www.udemy.com/course/the-complete-jenkins-course-for-developers-and-devops/\", \"Description\": \"Learn how testing fits into the modern development lifecycle. Master Git for version control and Jenkins for creating CI/CD pipelines to automatically run your tests.\", \"Learning Pace\": \"8-10 hours per week\", \"Alternative Free Link\": \"https://infyspringboard.onwingspan.com/web/en/app/toc/lex_auth_01297230491752857619_shared/overview\"}, {\"XPs\": 2000, \"Step\": \"Final Portfolio and Interview Mastery\", \"Badges\": \"Job Ready\", \"Duration\": 4, \"Provider\": \"Self-Directed - Free\", \"Course Link\": \"https://www.example.com/\", \"Description\": \"Consolidate all your learning. Build a comprehensive portfolio on GitHub showcasing 2-3 automation projects (Web, API, Mobile). Practice common QA interview questions, both technical and behavioral.\", \"Learning Pace\": \"10-15 hours per week\"}]}], \"Short Duration Path\": [{\"Phase\": \"Phase 1: Crash Course in QA Fundamentals (Weeks 1-4)\", \"Steps\": [{\"XPs\": 300, \"Step\": \"Software Testing and Agile Essentials\", \"Badges\": \"QA Apprentice\", \"Duration\": 2, \"Provider\": \"Infosys Springboard - Free\", \"Course Link\": \"https://infyspringboard.onwingspan.com/web/en/app/toc/lex_auth_0126742099395297282225_shared/overview\", \"Description\": \"A fast-paced introduction to the absolute essentials of manual testing, SDLC, Agile methodology, and the different types of testing you\'ll encounter on the job.\", \"Learning Pace\": \"15-20 hours per week\"}, {\"XPs\": 300, \"Step\": \"Practical Bug Reporting with Jira\", \"Badges\": \"Bug Hunter\", \"Duration\": 2, \"Provider\": \"Coursera - Free\", \"Course Link\": \"https://www.coursera.org/learn/jira-fundamentals\", \"Description\": \"Quickly get up to speed with the industry\'s #1 tool for bug tracking and project management. Learn to write clear, concise, and effective bug reports.\", \"Learning Pace\": \"10-15 hours per week\"}]}, {\"Phase\": \"Phase 2: Fast-Track to Automation (Weeks 5-12)\", \"Steps\": [{\"XPs\": 500, \"Step\": \"Python Programming for Absolute Beginners\", \"Badges\": \"Python Beginner\", \"Duration\": 4, \"Provider\": \"Educative - Partially Free\", \"Course Link\": \"https://www.educative.io/courses/learn-python-3-from-scratch\", \"Description\": \"This is a no-fluff, intensive course to learn the Python basics required for writing test automation scripts. Focus on variables, loops, conditions, functions, and basic data structures.\", \"Learning Pace\": \"15-20 hours per week\", \"Alternative Free Link\": \"https://www.youtube.com/watch?v=eWRfhZUzrAc\"}, {\"XPs\": 700, \"Step\": \"Hands-on Web Automation with Selenium\", \"Badges\": \"Selenium Scripter\", \"Duration\": 4, \"Provider\": \"Udemy - Paid\", \"Course Link\": \"https://www.udemy.com/course/the-complete-2021-selenium-webdriver-bootcamp/\", \"Description\": \"A highly practical, project-based course to get you writing Selenium scripts quickly. You will learn locators, interactions, waits, and how to handle common web testing scenarios.\", \"Learning Pace\": \"15-20 hours per week\"}]}, {\"Phase\": \"Phase 3: Essential Add-on Skills (Weeks 13-16)\", \"Steps\": [{\"XPs\": 400, \"Step\": \"Rapid API Testing with Postman\", \"Badges\": \"API Explorer\", \"Duration\": 2, \"Provider\": \"YouTube (Automation Step by Step) - Free\", \"Course Link\": \"https://www.youtube.com/watch?v=cfl9z49S9L0\", \"Description\": \"Quickly learn the fundamentals of API testing using Postman. This tutorial series is concise and covers everything you need to start testing REST APIs effectively.\", \"Learning Pace\": \"10-15 hours per week\"}, {\"XPs\": 300, \"Step\": \"SQL Fundamentals for Testers\", \"Badges\": \"SQL Querier\", \"Duration\": 2, \"Provider\": \"Kaggle Learn - Free\", \"Course Link\": \"https://www.kaggle.com/learn/intro-to-sql\", \"Description\": \"An interactive and fast-paced course to learn the basic SQL commands (SELECT, WHERE, JOIN) needed for backend data validation during testing.\", \"Learning Pace\": \"10-15 hours per week\"}]}, {\"Phase\": \"Phase 4: Project and Interview Blitz (Weeks 17-20)\", \"Steps\": [{\"XPs\": 200, \"Step\": \"Version Control with Git\", \"Badges\": \"Git User\", \"Duration\": 1, \"Provider\": \"YouTube (Traversy Media) - Free\", \"Course Link\": \"https://www.youtube.com/watch?v=RGOj5yH7evk\", \"Description\": \"A one-week crash course to learn the essential Git commands for managing your code and creating a portfolio on GitHub.\", \"Learning Pace\": \"10-15 hours per week\"}, {\"XPs\": 1000, \"Step\": \"Capstone Automation Project\", \"Badges\": \"Project Finisher\", \"Duration\": 2, \"Provider\": \"Self-Directed - Free\", \"Course Link\": \"http://automationpractice.com/index.php\", \"Description\": \"Apply everything you\'ve learned. Build a small but complete automation framework for a demo website. Automate 5-10 key test cases, structure your code well (e.g., using Page Object Model), and push it to GitHub.\", \"Learning Pace\": \"20+ hours per week\"}, {\"XPs\": 800, \"Step\": \"Intensive Interview Preparation\", \"Badges\": \"Interview Ready\", \"Duration\": 1, \"Provider\": \"YouTube (SDET- QA Automation Techie) - Free\", \"Course Link\": \"https://www.youtube.com/watch?v=2v5s9a_22aQ\", \"Description\": \"Focus entirely on job hunting. Practice common interview questions (manual, automation, SQL, and behavioral), refine your resume, and prepare to talk about your capstone project in detail.\", \"Learning Pace\": \"20+ hours per week\"}]}], \"Moderate Duration Path\": [{\"Phase\": \"Phase 1: QA Fundamentals & Agile Practices (Weeks 1-8)\", \"Steps\": [{\"XPs\": 500, \"Step\": \"Introduction to Software Development and Testing\", \"Badges\": \"QA Novice\", \"Duration\": 4, \"Provider\": \"Coursera - Partially Free\", \"Course Link\": \"https://www.coursera.org/learn/introduction-software-testing\", \"Description\": \"Start with the basics of software testing, including the testing lifecycle, principles, and different testing types. Understand how quality assurance fits into the Software Development Life Cycle (SDLC).\", \"Learning Pace\": \"10-12 hours per week\"}, {\"XPs\": 500, \"Step\": \"Mastering Agile and Bug Reporting with Jira\", \"Badges\": \"Agile Practitioner\", \"Duration\": 4, \"Provider\": \"Coursera - Partially Free\", \"Course Link\": \"https://www.coursera.org/learn/agile-atlassian-jira\", \"Description\": \"Learn the Agile and Scrum methodologies prevalent in the industry. Get hands-on experience with Jira for project management, writing user stories, and effective bug reporting.\", \"Learning Pace\": \"8-10 hours per week\"}]}, {\"Phase\": \"Phase 2: Core Automation Skills (Weeks 9-20)\", \"Steps\": [{\"XPs\": 800, \"Step\": \"Python for Automation\", \"Badges\": \"Python Coder\", \"Duration\": 6, \"Provider\": \"Coursera - Partially Free\", \"Course Link\": \"https://www.coursera.org/learn/python-crash-course\", \"Description\": \"Build a strong foundation in Python, the most popular language for test automation. This course from Google covers syntax, data structures, and the fundamentals needed to start writing automation scripts.\", \"Learning Pace\": \"10-12 hours per week\"}, {\"XPs\": 1000, \"Step\": \"Web Automation with Selenium WebDriver\", \"Badges\": \"Web Automator\", \"Duration\": 6, \"Provider\": \"Udemy - Paid\", \"Course Link\": \"https://www.udemy.com/course/selenium-webdriver-with-python3/\", \"Description\": \"Learn the industry-standard tool for web UI automation. This practical course will guide you from basic scripts to developing a functional test automation framework using the Page Object Model (POM).\", \"Learning Pace\": \"12-15 hours per week\"}]}, {\"Phase\": \"Phase 3: Expanding the Automation Toolkit (Weeks 21-30)\", \"Steps\": [{\"XPs\": 800, \"Step\": \"API Testing and Automation\", \"Badges\": \"API Specialist\", \"Duration\": 5, \"Provider\": \"Udemy - Paid\", \"Course Link\": \"https://www.udemy.com/course/postman-the-complete-guide/\", \"Description\": \"Master API testing, a critical skill for modern applications. Learn to use Postman for manual API testing and then automate your tests using Postman\'s collection runner and scripting capabilities.\", \"Learning Pace\": \"10-12 hours per week\", \"Alternative Free Link\": \"https://www.youtube.com/watch?v=VywxIQ2ZXw4\"}, {\"XPs\": 400, \"Step\": \"Database and SQL for Testers\", \"Badges\": \"Data Verifier\", \"Duration\": 2, \"Provider\": \"Coursera - Partially Free\", \"Course Link\": \"https://www.coursera.org/learn/sql-for-data-science\", \"Description\": \"Learn the SQL fundamentals required to query databases for test data setup and verification. This is an essential skill for ensuring data integrity.\", \"Learning Pace\": \"8-10 hours per week\"}, {\"XPs\": 600, \"Step\": \"Introduction to Performance Testing\", \"Badges\": \"Performance Scout\", \"Duration\": 3, \"Provider\": \"Infosys Springboard - Free\", \"Course Link\": \"https://infyspringboard.onwingspan.com/web/en/app/toc/lex_32810815411135890000_shared/overview\", \"Description\": \"Get an introduction to performance testing concepts and hands-on experience with JMeter. Understand how to simulate user load and identify performance bottlenecks in an application.\", \"Learning Pace\": \"10-12 hours per week\"}]}, {\"Phase\": \"Phase 4: DevOps, Portfolio & Job Readiness (Weeks 31-38)\", \"Steps\": [{\"XPs\": 400, \"Step\": \"Version Control with Git and GitHub\", \"Badges\": \"Git Collaborator\", \"Duration\": 3, \"Provider\": \"Coursera - Partially Free\", \"Course Link\": \"https://www.coursera.org/learn/introduction-git-github\", \"Description\": \"Learn how to manage your automation code using Git and collaborate with others using GitHub. This is a fundamental skill for any modern tech role.\", \"Learning Pace\": \"8-10 hours per week\"}, {\"XPs\": 500, \"Step\": \"CI/CD Integration Basics with Jenkins\", \"Badges\": \"Pipeline Builder\", \"Duration\": 2, \"Provider\": \"Udemy - Paid\", \"Course Link\": \"https://www.udemy.com/course/jenkins-from-zero-to-hero-become-a-devops-jenkins-master/\", \"Description\": \"Understand how to integrate your automated tests into a Continuous Integration pipeline using Jenkins. Learn to trigger test runs automatically on code changes.\", \"Learning Pace\": \"10-12 hours per week\"}, {\"XPs\": 1500, \"Step\": \"Build Your Portfolio and Prepare for Interviews\", \"Badges\": \"Interview Ace\", \"Duration\": 3, \"Provider\": \"Self-Directed - Free\", \"Course Link\": \"https://www.example.com/\", \"Description\": \"Create a GitHub repository to showcase your best automation projects (one UI, one API). Practice solving common coding problems asked in QA interviews and prepare answers for behavioral questions.\", \"Learning Pace\": \"12-15 hours per week\"}]}]}'),(55,30,'i want to become a CyberSecurity Analyst','2025-08-22 07:08:42',NULL),(56,30,'i want to become a CyberSecurity Analyst','2025-08-22 07:08:55',NULL),(57,30,'I want to become a CyberSecurity Analyst','2025-08-22 07:09:43','{\"Title\": \"Error: Could Not Parse Curriculum\", \"Long Duration Path\": [], \"Short Duration Path\": [], \"Moderate Duration Path\": []}'),(58,30,'I want to become  a cyber security analyst','2025-08-22 07:12:00',NULL),(59,29,'I want to become a Cyber Security Analyst','2025-09-25 09:24:37','{\"Title\": \"Cyber Security Analyst\", \"Long Duration Path\": [{\"Phase\": \"Phase 1: Advanced Foundations in IT & Networking (Weeks 1-12)\", \"Steps\": [{\"XPs\": 400, \"Step\": \"Deep Dive into Computer Networks\", \"Badges\": \"Network Architect\", \"Duration\": 8, \"Provider\": \"NPTEL - Free\", \"Course Link\": \"https://nptel.ac.in/courses/106105183\", \"Description\": \"Build a university-level, in-depth understanding of the TCP/IP protocol suite, network architecture, and routing protocols. This strong foundation is crucial for advanced security analysis.\", \"Learning Pace\": \"8-10 hours per week\"}, {\"XPs\": 250, \"Step\": \"Mastering the Linux Command Line\", \"Badges\": \"Linux Commander\", \"Duration\": 4, \"Provider\": \"edX / The Linux Foundation - Free\", \"Course Link\": \"https://www.edx.org/course/introduction-to-linux\", \"Description\": \"Linux is the backbone of many servers and security tools. Master the command line, file systems, and user management to become proficient in the environment where you\'ll spend most of your time.\", \"Learning Pace\": \"6-8 hours per week\"}]}, {\"Phase\": \"Phase 2: Operating Systems, DSA & Secure Scripting (Weeks 13-26)\", \"Steps\": [{\"XPs\": 400, \"Step\": \"Operating Systems Internals\", \"Badges\": \"OS Virtuoso\", \"Duration\": 8, \"Provider\": \"NPTEL - Free\", \"Course Link\": \"https://nptel.ac.in/courses/106105214\", \"Description\": \"Leverage your interest in OS by going deep into processes, threads, memory management, and file systems. Understanding these concepts is key to identifying and mitigating OS-level vulnerabilities.\", \"Learning Pace\": \"8-10 hours per week\"}, {\"XPs\": 350, \"Step\": \"Python for Security Automation\", \"Badges\": \"Python Paladin\", \"Duration\": 6, \"Provider\": \"Udemy - Paid\", \"Course Link\": \"https://www.udemy.com/course/automate/\", \"Description\": \"Learn Python to automate security tasks, parse logs, and build your own security tools. This is a high-demand skill that sets you apart. The paid course is highly practical and project-based.\", \"Learning Pace\": \"10-12 hours per week\", \"Alternative Free Link\": \"https://www.youtube.com/watch?v=8DvywoWv6fI\"}]}, {\"Phase\": \"Phase 3: Comprehensive Cybersecurity & CompTIA Security+ (Weeks 27-38)\", \"Steps\": [{\"XPs\": 400, \"Step\": \"Cybersecurity Fundamentals and Concepts\", \"Badges\": \"Security Strategist\", \"Duration\": 6, \"Provider\": \"Coursera - Partially Free\", \"Course Link\": \"https://www.coursera.org/professional-certificates/ibm-cybersecurity-analyst\", \"Description\": \"Cover the entire breadth of cybersecurity, including compliance, incident response, network security, and threat intelligence. This certificate provides a structured, job-ready curriculum.\", \"Learning Pace\": \"10-12 hours per week\"}, {\"XPs\": 600, \"Step\": \"Achieve CompTIA Security+ Certification\", \"Badges\": \"Certified Guardian\", \"Duration\": 6, \"Provider\": \"YouTube - Free\", \"Course Link\": \"https://www.youtube.com/playlist?list=PLG49S3nxzAnkL2ulFS3132mOVKuzz2SHr\", \"Description\": \"Security+ is the industry-standard foundational certification. This step focuses on studying for and passing the exam, which will significantly boost your resume.\", \"Learning Pace\": \"10-12 hours per week\"}]}, {\"Phase\": \"Phase 4: Advanced Security Operations & Threat Hunting (Weeks 39-52)\", \"Steps\": [{\"XPs\": 700, \"Step\": \"Become a Threat Hunter (CompTIA CySA+)\", \"Badges\": \"Cyber Threat Hunter\", \"Duration\": 8, \"Provider\": \"Udemy - Paid\", \"Course Link\": \"https://www.udemy.com/course/comptia-cybersecurity-analyst-cysa-cs0-002/\", \"Description\": \"Move beyond foundational security into proactive defense. Learn to analyze data, identify threats, and hunt for adversaries in a network. CySA+ is a highly respected analyst-level certification.\", \"Learning Pace\": \"10-12 hours per week\", \"Alternative Free Link\": \"https://tryhackme.com/path/outline/blueteam\"}, {\"XPs\": 500, \"Step\": \"Practical SIEM and Log Analysis\", \"Badges\": \"SIEM Sorcerer\", \"Duration\": 5, \"Provider\": \"Udemy - Paid\", \"Course Link\": \"https://www.udemy.com/course/splunk-for-beginners/\", \"Description\": \"Gain hands-on experience with a leading Security Information and Event Management (SIEM) tool. Learn to ingest data, search logs, create alerts, and build dashboards in Splunk.\", \"Learning Pace\": \"8-10 hours per week\", \"Alternative Free Link\": \"https://infyspringboard.onwingspan.com/web/en/app/toc/lex_auth_01267368564117504033_shared/overview\"}]}], \"Short Duration Path\": [{\"Phase\": \"Phase 1: Foundations and Asset Management (Weeks 1-5)\", \"Steps\": [{\"XPs\": 150, \"Step\": \"Foundations of Cybersecurity\", \"Badges\": \"Cybersecurity Initiate\", \"Duration\": 2, \"Provider\": \"Coursera - Partially Free\", \"Course Link\": \"https://www.coursera.org/learn/foundations-of-cybersecurity\", \"Description\": \"Start your accelerated journey with the first course in Google\'s certificate. Learn the core principles, concepts, and historical context of cybersecurity.\", \"Learning Pace\": \"10-15 hours per week\"}, {\"XPs\": 200, \"Step\": \"Managing Security Risks\", \"Badges\": \"Risk Assessor\", \"Duration\": 3, \"Provider\": \"Coursera - Partially Free\", \"Course Link\": \"https://www.coursera.org/learn/manage-security-risks\", \"Description\": \"Learn how to identify and protect an organization\'s assets. This course covers risk assessment frameworks, controls, and threat modeling in a practical way.\", \"Learning Pace\": \"10-15 hours per week\"}]}, {\"Phase\": \"Phase 2: Network and Endpoint Security (Weeks 6-10)\", \"Steps\": [{\"XPs\": 250, \"Step\": \"Networks and Network Security\", \"Badges\": \"Network Guardian\", \"Duration\": 3, \"Provider\": \"Coursera - Partially Free\", \"Course Link\": \"https://www.coursera.org/learn/networks-and-network-security\", \"Description\": \"Dive into computer networking and common network security solutions like firewalls and IDS/IPS. You\'ll use tools like Wireshark to analyze network traffic.\", \"Learning Pace\": \"10-15 hours per week\"}, {\"XPs\": 250, \"Step\": \"Linux and SQL for Security\", \"Badges\": \"Data Duelist\", \"Duration\": 2, \"Provider\": \"Coursera - Partially Free\", \"Course Link\": \"https://www.coursera.org/learn/linux-and-sql\", \"Description\": \"Quickly learn the essential Linux commands and SQL queries needed to manage systems and query security databases, which are daily tasks for a security analyst.\", \"Learning Pace\": \"10-15 hours per week\"}]}, {\"Phase\": \"Phase 3: Security Operations and Automation (Weeks 11-16)\", \"Steps\": [{\"XPs\": 300, \"Step\": \"Assets, Threats, and Vulnerabilities\", \"Badges\": \"Threat Spotter\", \"Duration\": 3, \"Provider\": \"Coursera - Partially Free\", \"Course Link\": \"https://www.coursera.org/learn/assets-threats-and-vulnerabilities\", \"Description\": \"Learn the core of security operations: monitoring for threats, identifying vulnerabilities, and understanding attacker tactics using frameworks like the MITRE ATT&CK.\", \"Learning Pace\": \"10-15 hours per week\"}, {\"XPs\": 350, \"Step\": \"Detection, Response, and Automation\", \"Badges\": \"Automation Ace\", \"Duration\": 3, \"Provider\": \"Coursera - Partially Free\", \"Course Link\": \"https://www.coursera.org/professional-certificates/google-cybersecurity\", \"Description\": \"Learn to use SIEM tools for detection, follow incident response playbooks, and use Python to automate repetitive security tasks, making you a more efficient analyst.\", \"Learning Pace\": \"10-15 hours per week\"}]}, {\"Phase\": \"Phase 4: Capstone and Career Readiness (Weeks 17-20)\", \"Steps\": [{\"XPs\": 500, \"Step\": \"Put It All Together: Security Operations\", \"Badges\": \"SOC Ready\", \"Duration\": 4, \"Provider\": \"Coursera - Partially Free\", \"Course Link\": \"https://www.coursera.org/learn/google-cybersecurity-capstone\", \"Description\": \"This final capstone project will have you perform a real-world security scenario, solidifying your skills and providing a valuable project for your portfolio. This phase also focuses on interview prep and resume building.\", \"Learning Pace\": \"12-18 hours per week\"}]}], \"Moderate Duration Path\": [{\"Phase\": \"Phase 1: Building the IT Foundation (Weeks 1-8)\", \"Steps\": [{\"XPs\": 200, \"Step\": \"Understand Computer Networking\", \"Badges\": \"Network Navigator\", \"Duration\": 4, \"Provider\": \"Coursera - Partially Free\", \"Course Link\": \"https://www.coursera.org/learn/computer-networking\", \"Description\": \"A solid understanding of networking is non-negotiable. This course covers the essentials of TCP/IP, DNS, and HTTP in a clear and concise way.\", \"Learning Pace\": \"8-10 hours per week\"}, {\"XPs\": 200, \"Step\": \"Learn to use Linux\", \"Badges\": \"Linux Ranger\", \"Duration\": 4, \"Provider\": \"Coursera / The Linux Foundation - Partially Free\", \"Course Link\": \"https://www.coursera.org/learn/linux-for-developers\", \"Description\": \"Get comfortable working in a Linux environment. You will learn essential commands, shell scripting, and system administration basics needed for security analysis.\", \"Learning Pace\": \"6-8 hours per week\"}]}, {\"Phase\": \"Phase 2: Core Cybersecurity Principles & Tools (Weeks 9-20)\", \"Steps\": [{\"XPs\": 350, \"Step\": \"Introduction to Cybersecurity\", \"Badges\": \"Cybersecurity Apprentice\", \"Duration\": 6, \"Provider\": \"Coursera - Partially Free\", \"Course Link\": \"https://www.coursera.org/professional-certificates/ibm-cybersecurity-analyst\", \"Description\": \"Begin the IBM certificate to learn about cybersecurity roles, processes, and the threat landscape. You will cover network security, endpoint protection, and cyber attack frameworks.\", \"Learning Pace\": \"10-12 hours per week\"}, {\"XPs\": 300, \"Step\": \"Python for Security Scripts\", \"Badges\": \"Python Scripter\", \"Duration\": 6, \"Provider\": \"Coursera - Partially Free\", \"Course Link\": \"https://www.coursera.org/specializations/python\", \"Description\": \"Learn the fundamentals of Python, a critical language for automating tasks and data analysis in cybersecurity. This specialization provides a strong programming foundation.\", \"Learning Pace\": \"8-10 hours per week\"}]}, {\"Phase\": \"Phase 3: Security Operations and Analysis (Weeks 21-30)\", \"Steps\": [{\"XPs\": 400, \"Step\": \"Security Operations and Incident Response\", \"Badges\": \"Incident Responder\", \"Duration\": 5, \"Provider\": \"Coursera - Partially Free\", \"Course Link\": \"https://www.coursera.org/professional-certificates/ibm-cybersecurity-analyst\", \"Description\": \"Continue with the IBM certificate, focusing on real-world analyst skills like threat intelligence, vulnerability assessment, and incident response using tools like Wireshark and IBM QRadar.\", \"Learning Pace\": \"10-12 hours per week\"}, {\"XPs\": 350, \"Step\": \"Hands-on Security Practice\", \"Badges\": \"Practical Defender\", \"Duration\": 5, \"Provider\": \"TryHackMe - Partially Free\", \"Course Link\": \"https://tryhackme.com/path/outline/jrpenetrationtester\", \"Description\": \"Theory is good, but practice is better. Apply your knowledge in hands-on labs. While labeled \'Penetration Tester\', the initial modules are essential for defensive roles to understand offensive tactics.\", \"Learning Pace\": \"6-8 hours per week\"}]}, {\"Phase\": \"Phase 4: Certification and Career Launch (Weeks 31-38)\", \"Steps\": [{\"XPs\": 500, \"Step\": \"Prepare for CompTIA Security+\", \"Badges\": \"Certified Defender\", \"Duration\": 5, \"Provider\": \"YouTube - Free\", \"Course Link\": \"https://www.youtube.com/playlist?list=PLG49S3nxzAnkL2ulFS3132mOVKuzz2SHr\", \"Description\": \"Focus on passing the CompTIA Security+ exam. This certification is a benchmark for entry-level cybersecurity roles and is highly valued by employers.\", \"Learning Pace\": \"10-12 hours per week\"}, {\"XPs\": 400, \"Step\": \"Capstone Project and Job Hunting\", \"Badges\": \"Job Ready Analyst\", \"Duration\": 3, \"Provider\": \"Coursera - Partially Free\", \"Course Link\": \"https://www.coursera.org/learn/ibm-cybersecurity-analyst-capstone\", \"Description\": \"Complete the final capstone project to simulate a real-world security breach investigation. Use this project to build your portfolio, refine your resume, and start applying for jobs.\", \"Learning Pace\": \"8-10 hours per week\"}]}]}'),(60,29,'i want to become a fashion designer','2025-09-25 09:59:09','{\"Title\": \"Technical Fashion Designer\", \"Long Duration Path\": [{\"Phase\": \"Phase 1: Foundational Immersion (Weeks 1-12)\", \"Steps\": [{\"XPs\": 150, \"Step\": \"Understanding the World of Fashion\", \"Badges\": \"Fashion Historian\", \"Duration\": 4, \"Provider\": \"Coursera (MoMA) - Free to Audit\", \"Course Link\": \"https://www.coursera.org/learn/fashion-design\", \"Description\": \"Build a strong foundation by exploring the history of fashion, understanding how designers think, and learning about the lifecycle of a garment. This provides the cultural context for your technical work.\", \"Learning Pace\": \"6-8 hours per week\"}, {\"XPs\": 200, \"Step\": \"Mastering Figure Drawing for Fashion\", \"Badges\": \"Sketching Apprentice\", \"Duration\": 4, \"Provider\": \"Udemy - Paid\", \"Course Link\": \"https://www.udemy.com/course/fashion-figure-drawing-step-by-step-for-beginners/\", \"Description\": \"Learn the fundamentals of drawing the fashion figure (croquis). This paid course is highly structured for beginners, but the free alternative from industry expert Zoe Hong is also excellent.\", \"Learning Pace\": \"8-10 hours per week\", \"Alternative Free Link\": \"https://www.youtube.com/playlist?list=PLwQq1-SdsNvYk_rG4Xp_2fV_1n5I-b5p4\"}, {\"XPs\": 200, \"Step\": \"Introduction to Textiles and Materials\", \"Badges\": \"Material Novice\", \"Duration\": 4, \"Provider\": \"Infosys Springboard - Free\", \"Course Link\": \"https://www.infosys springboard.onwingspan.com/en/app/toc/lex_auth_0135626920251719681342_shared/overview\", \"Description\": \"Leverage your engineering mindset to understand the science of textiles. Learn about different fibers, weaves, and fabric properties, which is crucial for both design and production.\", \"Learning Pace\": \"6-8 hours per week\"}]}, {\"Phase\": \"Phase 2: Mastering Digital Design Tools (Weeks 13-28)\", \"Steps\": [{\"XPs\": 300, \"Step\": \"Digital Sketching and Rendering with Adobe Photoshop\", \"Badges\": \"Digital Painter\", \"Duration\": 6, \"Provider\": \"Udemy - Paid\", \"Course Link\": \"https://www.udemy.com/course/adobe-photoshop-for-fashion-design-fashion-illustration/\", \"Description\": \"Translate your hand-drawing skills to the digital canvas. Learn to render textures, create mood boards, and professionally present your ideas using Adobe Photoshop.\", \"Learning Pace\": \"8-10 hours per week\"}, {\"XPs\": 350, \"Step\": \"Technical Design with Adobe Illustrator\", \"Badges\": \"CAD Specialist\", \"Duration\": 6, \"Provider\": \"Udemy - Paid\", \"Course Link\": \"https://www.udemy.com/course/adobe-illustrator-for-fashion-design-fashion-flats/\", \"Description\": \"This is a critical skill. Learn to create professional technical flats—the blueprints for garments. Your engineering precision will be a huge asset here. This paid course is industry-standard.\", \"Learning Pace\": \"10-12 hours per week\"}, {\"XPs\": 400, \"Step\": \"Entering the World of 3D Fashion with CLO 3D\", \"Badges\": \"3D Virtuoso\", \"Duration\": 4, \"Provider\": \"Udemy - Paid\", \"Course Link\": \"https://www.udemy.com/course/mastering-clo-3d/\", \"Description\": \"Dive into 3D garment creation. CLO 3D is revolutionizing the industry by reducing waste and speeding up prototyping. Your tech background gives you a significant edge in mastering this powerful software.\", \"Learning Pace\": \"10-12 hours per week\"}]}, {\"Phase\": \"Phase 3: Principles of Garment Construction (Weeks 29-40)\", \"Steps\": [{\"XPs\": 350, \"Step\": \"Pattern Making and Draping Fundamentals\", \"Badges\": \"Pattern Architect\", \"Duration\": 6, \"Provider\": \"Udemy - Paid\", \"Course Link\": \"https://www.udemy.com/course/pattern-making-for-fashion-design-the-comprehensive-guide/\", \"Description\": \"Understand the engineering behind clothing. Learn how 2D patterns turn into 3D garments. This theoretical knowledge is vital even when working digitally in CLO 3D.\", \"Learning Pace\": \"8-10 hours per week\", \"Alternative Free Link\": \"https://www.youtube.com/playlist?list=PLvEh9fNEg86Xb-ldkS_6Nif3qC17GvZE_\"}, {\"XPs\": 300, \"Step\": \"Garment Construction and Sewing Theory\", \"Badges\": \"Stitching Scholar\", \"Duration\": 6, \"Provider\": \"Skillshare - Paid (Offers Free Trial)\", \"Course Link\": \"https://www.skillshare.com/en/classes/Sewing-101-The-Basics/1841315848\", \"Description\": \"Learn about seams, stitches, and the order of operations for constructing a garment. While hands-on practice is best, this course provides the essential knowledge to create realistic 3D models and communicate with manufacturers.\", \"Learning Pace\": \"6-8 hours per week\"}]}, {\"Phase\": \"Phase 4: Specialization and Professional Portfolio (Weeks 41-52)\", \"Steps\": [{\"XPs\": 250, \"Step\": \"The Business of Fashion\", \"Badges\": \"Industry Insider\", \"Duration\": 4, \"Provider\": \"Coursera (Bocconi) - Free to Audit\", \"Course Link\": \"https://www.coursera.org/learn/mafash\", \"Description\": \"Understand the business side of the industry: branding, marketing, retail, and supply chain. This knowledge is key to designing marketable products and landing a high-paying job.\", \"Learning Pace\": \"5-7 hours per week\"}, {\"XPs\": 1000, \"Step\": \"Capstone Project: Design and Develop a Collection\", \"Badges\": \"Portfolio Pro\", \"Duration\": 8, \"Provider\": \"Self-Directed Project - Free\", \"Course Link\": \"https://www.wikihow.com/Make-a-Fashion-Portfolio\", \"Description\": \"This is the culmination of all your learning. Design a cohesive mini-collection (5-7 outfits) from concept to final renders. Create technical flats, 3D prototypes in CLO, and a stunning digital presentation. This project will be the centerpiece of your portfolio.\", \"Learning Pace\": \"15+ hours per week\"}]}], \"Short Duration Path\": [{\"Phase\": \"Phase 1: Crash Course in Fashion Essentials (Weeks 1-4)\", \"Steps\": [{\"XPs\": 100, \"Step\": \"Fashion Design Fundamentals\", \"Badges\": \"Design Novice\", \"Duration\": 2, \"Provider\": \"Udemy - Paid\", \"Course Link\": \"https://www.udemy.com/course/fashion-design-course/\", \"Description\": \"A high-speed overview of the absolute essentials: design principles, basic sketching, color theory, and mood board creation. The goal is to get you up to speed fast.\", \"Learning Pace\": \"10-12 hours per week\"}, {\"XPs\": 200, \"Step\": \"Rapid Technical Sketching with Illustrator\", \"Badges\": \"Speedy Sketcher\", \"Duration\": 2, \"Provider\": \"Skillshare - Paid (Offers Free Trial)\", \"Course Link\": \"https://www.skillshare.com/en/classes/Crash-Course-in-Adobe-Illustrator-for-Fashion-Design-The-BASICS/2143031093\", \"Description\": \"This path skips hand-drawing and goes straight to the industry-standard software. Learn the basics of creating technical flats in Illustrator at an accelerated pace.\", \"Learning Pace\": \"12-15 hours per week\"}]}, {\"Phase\": \"Phase 2: Intensive 3D Digital Fashion Creation (Weeks 5-16)\", \"Steps\": [{\"XPs\": 750, \"Step\": \"Mastering CLO 3D for Digital Prototyping\", \"Badges\": \"3D Specialist\", \"Duration\": 12, \"Provider\": \"Udemy - Paid\", \"Course Link\": \"https://www.udemy.com/course/clo-3d-for-beginners-from-zero-to-hero/\", \"Description\": \"This is the core of the short-duration path. Your goal is to become a specialist in 3D fashion design, a highly sought-after and well-paid skill. This intensive, project-based course is your ticket. Your tech background is a massive advantage here.\", \"Learning Pace\": \"15-20 hours per week\"}]}, {\"Phase\": \"Phase 3: Express Portfolio and Job Hunt (Weeks 17-22)\", \"Steps\": [{\"XPs\": 500, \"Step\": \"Building a Specialized 3D Fashion Portfolio\", \"Badges\": \"Digital Portfolio Pro\", \"Duration\": 4, \"Provider\": \"Self-Directed Project (Guided by YouTube) - Free\", \"Course Link\": \"https://www.youtube.com/watch?v=w7j2cYLm0NA\", \"Description\": \"Focus exclusively on your high-tech skills. Create 3-5 stunning, fully-realized digital garments in CLO 3D. Showcase them with high-quality renders and animations in a clean online portfolio.\", \"Learning Pace\": \"15+ hours per week\"}, {\"XPs\": 150, \"Step\": \"Career Kickstarter\", \"Badges\": \"Job Ready\", \"Duration\": 2, \"Provider\": \"Infosys Springboard - Free\", \"Course Link\": \"https://www.infosys springboard.onwingspan.com/en/app/toc/lex_auth_0135627023307571201402_shared/overview\", \"Description\": \"Tailor your resume to highlight your unique combination of technical and design skills. Learn how to market yourself as a \'Technical Fashion Designer\' and target companies that are leading in digital innovation.\", \"Learning Pace\": \"8-10 hours per week\"}]}], \"Moderate Duration Path\": [{\"Phase\": \"Phase 1: Fashion Fundamentals (Weeks 1-8)\", \"Steps\": [{\"XPs\": 150, \"Step\": \"Introduction to Fashion Design and History\", \"Badges\": \"Design Novice\", \"Duration\": 4, \"Provider\": \"Coursera (MoMA) - Free to Audit\", \"Course Link\": \"https://www.coursera.org/learn/fashion-design\", \"Description\": \"A fast-paced introduction to the history, language, and core concepts of fashion design to build a solid contextual base.\", \"Learning Pace\": \"8-10 hours per week\"}, {\"XPs\": 200, \"Step\": \"Essential Fashion Sketching and Illustration\", \"Badges\": \"Sketching Apprentice\", \"Duration\": 4, \"Provider\": \"Udemy - Paid\", \"Course Link\": \"https://www.udemy.com/course/fashion-illustration-manga-and-anime/\", \"Description\": \"A practical, project-based course to quickly get your sketching skills up to a presentable level, focusing on a modern, stylized approach.\", \"Learning Pace\": \"10-12 hours per week\"}]}, {\"Phase\": \"Phase 2: Digital Design Proficiency (Weeks 9-22)\", \"Steps\": [{\"XPs\": 350, \"Step\": \"Technical Flats in Adobe Illustrator\", \"Badges\": \"CAD Specialist\", \"Duration\": 6, \"Provider\": \"YouTube (Zoe Hong) - Free\", \"Course Link\": \"https://www.youtube.com/playlist?list=PLwQq1-SdsNvbgaV_pep4h4eY4J1aC5gGg\", \"Description\": \"Learn the most crucial software skill for any fashion designer: creating technical flats. This free, in-depth playlist by an industry professional is a fantastic resource.\", \"Learning Pace\": \"10-12 hours per week\"}, {\"XPs\": 450, \"Step\": \"3D Prototyping with CLO 3D\", \"Badges\": \"3D Virtuoso\", \"Duration\": 8, \"Provider\": \"YouTube (Daniela Paz) - Free\", \"Course Link\": \"https://www.youtube.com/playlist?list=PL4R64F6A2g_P2Oa_x2ycth2crTPEdJd_2\", \"Description\": \"Dive deep into the most in-demand tech skill in fashion. This comprehensive free playlist will take you from the basics of CLO 3D to creating complex garments, leveraging your technical aptitude.\", \"Learning Pace\": \"12-15 hours per week\"}]}, {\"Phase\": \"Phase 3: Construction & Business Acumen (Weeks 23-30)\", \"Steps\": [{\"XPs\": 250, \"Step\": \"Understanding Garment Construction and Patterns\", \"Badges\": \"Pattern Architect\", \"Duration\": 4, \"Provider\": \"Coursera (Project Network) - Paid (but low cost)\", \"Course Link\": \"https://www.coursera.org/projects/fashion-design-concept-to-production\", \"Description\": \"A guided project that covers the entire design-to-production process, including the theory of pattern making and construction. This gives essential context to your digital work.\", \"Learning Pace\": \"8-10 hours per week\"}, {\"XPs\": 200, \"Step\": \"The Business of Fashion Essentials\", \"Badges\": \"Industry Insider\", \"Duration\": 4, \"Provider\": \"Infosys Springboard - Free\", \"Course Link\": \"https://www.infosys springboard.onwingspan.com/en/app/toc/lex_auth_0135627063462625281430_shared/overview\", \"Description\": \"Quickly learn the fundamentals of the fashion business, from branding and marketing to the supply chain, to ensure your designs are commercially viable.\", \"Learning Pace\": \"6-8 hours per week\"}]}, {\"Phase\": \"Phase 4: Capstone Portfolio Project (Weeks 31-38)\", \"Steps\": [{\"XPs\": 1000, \"Step\": \"Building a High-Impact Digital Portfolio\", \"Badges\": \"Portfolio Pro\", \"Duration\": 8, \"Provider\": \"Self-Directed Project (Guided by YouTube) - Free\", \"Course Link\": \"https://www.youtube.com/watch?v=sI9d_aV0uM8\", \"Description\": \"Apply all your skills to create a focused, 4-6 piece digital collection. Develop concepts, create technical flats in Illustrator and realistic 3D renders in CLO. Compile everything into a professional online portfolio ready for job applications.\", \"Learning Pace\": \"15+ hours per week\"}]}]}'),(61,29,'I want to become a Data Scientist ','2025-10-23 06:13:13',NULL);
